// Extraer información del archivo recibido
const fileData = $input.item.binary.data;
const fileName = $input.item.json.filename || 'factura.pdf';
const fileExtension = fileName.split('.').pop().toLowerCase();
const supplierName = $input.item.json.supplier_name || null;
const supplierVat = $input.item.json.supplier_vat || null;

// Determinar el proveedor basado en el nombre o VAT
let proveedorDetectado = null;
let promptEspecifico = null;

if (supplierName) {
  if (supplierName.toUpperCase().includes('NEVIR')) {
    proveedorDetectado = 'NEVIR';
    promptEspecifico = 'Extrae de esta factura de NEVIR: número de factura (en formato NVR-XXXXX), fecha, CIF (B84201219), totales con IVA desglosado y recargo de equivalencia, y líneas de productos con códigos que siguen el patrón NVR-XXXXX.';
  } else if (supplierName.toUpperCase().includes('ABRILA')) {
    proveedorDetectado = 'ABRILA';
    promptEspecifico = 'Extrae de esta factura de ABRILA: número de factura, fecha, CIF, totales con IVA desglosado, y líneas de productos con sus referencias específicas.';
  } else if (supplierName.toUpperCase().includes('MIELECTRO')) {
    proveedorDetectado = 'MIELECTRO';
    promptEspecifico = 'Extrae de esta factura de MIELECTRO: número de factura, fecha, CIF, totales con IVA desglosado, y líneas de productos con sus referencias específicas.';
  }
}

// Si no se detectó por nombre, intentar por VAT
if (!proveedorDetectado && supplierVat) {
  if (supplierVat === 'B84201219') {
    proveedorDetectado = 'NEVIR';
    promptEspecifico = 'Extrae de esta factura de NEVIR: número de factura (en formato NVR-XXXXX), fecha, CIF (B84201219), totales con IVA desglosado y recargo de equivalencia, y líneas de productos con códigos que siguen el patrón NVR-XXXXX.';
  }
  // Añadir más proveedores por VAT si es necesario
}

// Prompt genérico si no se detectó un proveedor específico
if (!promptEspecifico) {
  promptEspecifico = 'Extrae de esta factura: número de factura, fecha, CIF/NIF del proveedor, nombre del proveedor, totales con IVA desglosado, y líneas de productos con sus referencias, cantidades y precios.';
}

// Verificar si el archivo está en caché (simulado)
const estaEnCache = false; // Aquí se implementaría la lógica real de caché

// Preparar la salida
return {
  json: {
    fileData,
    fileName,
    fileExtension,
    supplierName,
    supplierVat,
    proveedorDetectado,
    promptEspecifico,
    estaEnCache
  }
};

// Procesar la respuesta de Mistral OCR
const mistralResponse = $input.item.json;
const proveedorDetectado = $input.item.json.proveedorDetectado || 'Desconocido';

// Extraer datos estructurados según el proveedor
let datosEstructurados = {};

if (mistralResponse && mistralResponse.text) {
  const textoOCR = mistralResponse.text;

  // Extraer número de factura
  let numeroFactura = null;
  const regexNumFactura = /(?:factura|número)[:\s]*(\w+[-\d]+)/i;
  const matchNumFactura = textoOCR.match(regexNumFactura);
  if (matchNumFactura) {
    numeroFactura = matchNumFactura[1];
  }

  // Extraer fecha
  let fechaFactura = null;
  const regexFecha = /(?:fecha)[:\s]*(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4})/i;
  const matchFecha = textoOCR.match(regexFecha);
  if (matchFecha) {
    fechaFactura = matchFecha[1];
  }

  // Extraer CIF/NIF
  let cifNif = null;
  const regexCif = /(?:CIF|NIF)[:\s]*([A-Z0-9]{9})/i;
  const matchCif = textoOCR.match(regexCif);
  if (matchCif) {
    cifNif = matchCif[1];
  }

  // Extraer totales
  let baseImponible = null;
  let importeIva = null;
  let totalFactura = null;

  const regexBase = /(?:base|imponible)[:\s]*(\d+[.,]\d{2})/i;
  const matchBase = textoOCR.match(regexBase);
  if (matchBase) {
    baseImponible = matchBase[1].replace(',', '.');
  }

  const regexIva = /(?:IVA)[:\s]*(\d+[.,]\d{2})/i;
  const matchIva = textoOCR.match(regexIva);
  if (matchIva) {
    importeIva = matchIva[1].replace(',', '.');
  }

  const regexTotal = /(?:total)[:\s]*(\d+[.,]\d{2})/i;
  const matchTotal = textoOCR.match(regexTotal);
  if (matchTotal) {
    totalFactura = matchTotal[1].replace(',', '.');
  }

  // Extraer líneas de productos (simplificado)
  const lineasProductos = [];

  // Para NEVIR, buscar códigos con patrón NVR-XXXXX
  if (proveedorDetectado === 'NEVIR') {
    const regexProductosNevir = /NVR-\d{5}/g;
    const codigosProductos = textoOCR.match(regexProductosNevir) || [];

    codigosProductos.forEach(codigo => {
      lineasProductos.push({
        codigo: codigo,
        descripcion: `Producto ${codigo}`,
        cantidad: 1,
        precio: 0
      });
    });
  } else {
    // Para otros proveedores, intentar extraer líneas genéricas
    // Esta es una implementación muy simplificada
    const lineas = textoOCR.split('\n');

    for (const linea of lineas) {
      // Buscar líneas que parezcan productos (contienen números y €)
      if (linea.match(/\d+/) && linea.includes('€')) {
        lineasProductos.push({
          descripcion: linea.trim(),
          cantidad: 1,
          precio: 0
        });
      }
    }
  }

  // Construir objeto estructurado
  datosEstructurados = {
    numeroFactura,
    fechaFactura,
    cifNif,
    proveedor: proveedorDetectado,
    baseImponible: parseFloat(baseImponible || 0),
    importeIva: parseFloat(importeIva || 0),
    totalFactura: parseFloat(totalFactura || 0),
    lineasProductos
  };
}

// Guardar en caché (simulado)
// Aquí se implementaría la lógica real de guardado en caché

return {
  json: {
    success: true,
    datosOCR: datosEstructurados,
    textoCompleto: mistralResponse.text,
    proveedor: proveedorDetectado
  }
};

// Obtener datos de caché (simulado)
// Aquí se implementaría la lógica real de obtención desde caché

return {
  json: {
    success: true,
    datosOCR: {
      numeroFactura: "CACHE-12345",
      fechaFactura: "01/07/2025",
      cifNif: "B12345678",
      proveedor: $input.item.json.proveedorDetectado || "Desconocido",
      baseImponible: 100.00,
      importeIva: 21.00,
      totalFactura: 121.00,
      lineasProductos: [
        {
          codigo: "PROD-001",
          descripcion: "Producto de caché",
          cantidad: 1,
          precio: 100.00
        }
      ]
    },
    textoCompleto: "Datos recuperados desde caché",
    proveedor: $input.item.json.proveedorDetectado || "Desconocido",
    fromCache: true
  }
};

// Validar datos OCR
const datosOCR = $input.item.json.datosOCR;
const errores = [];
let datosValidos = true;

// Validar número de factura
if (!datosOCR.numeroFactura) {
  errores.push("Número de factura no detectado");
  datosValidos = false;
}

// Validar fecha
if (!datosOCR.fechaFactura) {
  errores.push("Fecha de factura no detectada");
  datosValidos = false;
}

// Validar CIF/NIF
if (datosOCR.cifNif) {
  // Validar formato de CIF/NIF español
  const regexCIF = /^[A-Z0-9]{9}$/;
  if (!regexCIF.test(datosOCR.cifNif)) {
    errores.push("Formato de CIF/NIF inválido");
    datosValidos = false;
  }

  // Aquí se implementaría la validación del dígito de control
}

// Validar totales
if (datosOCR.totalFactura <= 0) {
  errores.push("Total de factura inválido");
  datosValidos = false;
}

// Validar líneas de productos
if (!datosOCR.lineasProductos || datosOCR.lineasProductos.length === 0) {
  errores.push("No se detectaron líneas de productos");
  datosValidos = false;
}

// Buscar proveedor en Odoo (simulado)
// Aquí se implementaría la lógica real de búsqueda de proveedor
let supplierId = 0;
if (datosOCR.cifNif === "B84201219") {
  supplierId = 1; // ID de NEVIR en Odoo (ejemplo)
}

return {
  json: {
    datosOCR,
    datosValidos,
    errores,
    supplier_id: supplierId,
    token: $input.item.json.token
  }
};

